import React, { useState, useRef } from "react";
import defaultImg from "../../image/default.jpg";
import background1 from "../../image/background1.jpg";
import { Formik, Field, Form } from "formik";
import { validationSchema } from "./application.schema";

function Application() {
  const saveProfile = JSON.parse(localStorage.getItem("userProfile")) || {};
  const saveImg = localStorage.getItem("profileImg");

  const [user, setUser] = useState({
    profileImg: saveImg || defaultImg,
  });

  const fileInputRef = useRef();

  const handleProfileChange = (event) => {
    const file = event.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => {
        const imgData = e.target.result;
        localStorage.setItem("profileImg", imgData);
        setUser({ profileImg: imgData });
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <div
      className="profile-background"
      style={{ backgroundImage: `url(${background1})` }}
    >
      <div className="profile-card transparent-card">
        <h3 className="text-center mb-4">Edit Profile</h3>

        {/* Profile Image */}
        <div className="text-center mb-3">
          <img
            src={user.profileImg}
            alt="Profile"
            className="profile-pic"
          />
          <br />
          <button
            type="button"
            className="btn btn-glow mt-2 change-image"
            onClick={() => fileInputRef.current.click()}
          >
            Change Image
          </button>
          <input
            type="file"
            accept="image/*"
            style={{ display: "none" }}
            ref={fileInputRef}
            onChange={handleProfileChange}
          />
        </div>

        {/* Profile Form */}
        <Formik
          initialValues={{
            firstName: saveProfile.firstName || "",
            lastName: saveProfile.lastName || "",
            age: saveProfile.age || "",
            email: saveProfile.email || "",
            mobile: saveProfile.mobile || "",
            height: saveProfile.height || "",
            institute: saveProfile.institute || "",
            bloodGroup: saveProfile.bloodGroup || "",
            district: saveProfile.district || "",
            birthday: saveProfile.birthday || "",
            gender: saveProfile.gender || "",
          }}
          validationSchema={validationSchema}
          onSubmit={(values) => {
            const profileData = { ...values, profileImg: user.profileImg };
            localStorage.setItem("userProfile", JSON.stringify(profileData));
            localStorage.setItem("profileImg", user.profileImg);
            alert("✅ Profile updated successfully!");
          }}
        >
          {(formik) => (
            <Form>
              <div className="row mb-3">
                <div className="col">
                  <label>First Name</label>
                  <Field id="first_name" name="firstName" placeholder="Enter first name" />
                </div>
                <div className="col">
                  <label>Last Name</label>
                  <Field id="last_name" name="lastName" placeholder="Enter last name" />
                </div>
              </div>

              <div className="row mb-3">
                <div className="col">
                  <label >Age</label>
                  <Field id="Age" name="age" placeholder="Enter your age" />
                </div>
                <div className="col">
                  <label>Gender</label>
                  <Field id="Gender" name="gender" placeholder="Male / Female" />
                </div>
              </div>

              <div className="mb-3">
                <label>Email <span style={{ color: "red" }}>*</span></label>
                <Field id="Email" name="email" placeholder="Enter your email" />
                {formik.touched.email && formik.errors.email && (
                  <div className="text-danger">{formik.errors.email}</div>
                )}
              </div>

              <div className="mb-3">
                <label>Mobile</label>
                <Field id="Mobile" name="mobile" placeholder="01..." />
              </div>

              <div className="row mb-3">
                <div className="col">
                  <label>Height</label>
                  <Field id="Height" name="height" placeholder="Enter your height"/>
                </div>
                <div className="col">
                  <label>Blood Group</label>
                  <Field id="Blood_Group" name="bloodGroup" placeholder="e.g. O+" />
                </div>
              </div>

              <div className="mb-3">
                <label>Institute</label>
                <Field id="Institute" name="institute" placeholder="Your Institute" />
              </div>

              <div className="row mb-3">
                <div className="col">
                  <label>District</label>
                  <Field id="District" name="district" placeholder="e.g. Dhaka" />
                </div>
                <div className="col">
                  <label>Birthday</label>
                  <Field id="Birthday" name="birthday" placeholder="DD-MM-YYYY" />
                </div>
              </div>

              <button type="submit" className="btn btn-success w-100 change-image">
                Save Changes
              </button>
            </Form>
          )}
        </Formik>
      </div>
    </div>
  );
}

export default Application;
